static unsigned int get_sve_vector_length(void)
{
    unsigned long zcr;

    /* ZCR_EL1에서 벡터 길이 읽기 */
    asm volatile("mrs %0, ___" : "=r" (zcr));

    /* 벡터 길이 = (LEN + 1) * 128 bits */
    return ((zcr & 0xf) + 1) * ___;
